func Solve(s string) bool {
  stack := []rune{}
  pairs := map[rune]rune{')':'(', ']':'[', '}':'{'}
  for _, ch := range []rune(s) {
    if ch=='(' || ch=='[' || ch=='{' {
      stack = append(stack, ch)
    } else if ch==')' || ch==']' || ch=='}' {
      if len(stack)==0 { return false }
      top := stack[len(stack)-1]
      stack = stack[:len(stack)-1]
      if top != pairs[ch] { return false }
    }
  }
  return len(stack)==0
}

